        v_root = find(v)
        if u_root == v_root:
            return
        if rank[u_root] > rank[v_root]:
            parent[v_root] = u_root
            rank[u_root] += rank[v_root]
        else:
            parent[u_root] = v_root
            rank[v_root] += rank[u_root]

    for u, v in connections:
        union(u, v)

    # Now, for each component, we need to track the minimal online node
    # We'll use a dictionary: key is the root, value is a min-heap of online nodes
    from heapq import heappush, heappop
    component_heaps = defaultdict(list)
    online_status = [True] * (c + 1)  # 1-based

    # Initialize: all nodes are online, push each to its component's heap
    for u in range(1, c + 1):
        root = find(u)
        heappush(component_heaps[root], u)

    result = []
    for query in queries:
        type_q, x = query
        if type_q == 1:
            root_x = find(x)
            if online_status[x]:
                result.append(x)
            else:
                # Find the minimal online node in the component
                heap = component_heaps[root_x]
                found = -1
                # We might have outdated entries in the heap (nodes that are offline)
                while heap:
                    current_min = heap[0]
                    if online_status[current_min]:
                        found = current_min
                        break
                    else:
                        heappop(heap)
                result.append(found)
        elif type_q == 2:
            if online_status[x]:
                online_status[x] = False
    return result
